 1	import { Card, CardBody, Flex, FlexItem, Text, TextVariants } from '@patternfly/react-core';
 2	import * as React from 'react';
 3	
 4	export type Severity = 'critical' | 'warning' | 'info';
 5	
 6	export interface HealthMetricCardProps {
 7	  severity: Severity;
 8	  label: string;
 9	  total: number;
10	  detail?: string;
11	}
12	
13	export const HealthMetricCard: React.FC<HealthMetricCardProps> = ({ severity, label, total, detail }) => {
14	  return (
15	    <Card className={`health-metric-card ${severity}`}>
16	      <CardBody>
17	        <Flex direction={{ default: 'column' }} spaceItems={{ default: 'spaceItemsNone' }}>
18	          <FlexItem>
19	            <Text component={TextVariants.small} className="metric-label">
20	              {label}
21	            </Text>
22	          </FlexItem>
23	          <FlexItem>
24	            <Text component={TextVariants.h1} className="metric-value">
25	              {total}
26	            </Text>
27	          </FlexItem>
28	          {total > 0 && detail && (
29	            <FlexItem>
30	              <Text component={TextVariants.small} className="metric-detail">
31	                {detail}
32	              </Text>
33	            </FlexItem>
34	          )}
35	        </Flex>
36	      </CardBody>
37	    </Card>
38	  );
39	};

